#include <stdio.h>
#include <string.h>

int hasPattern(const char *s, const char *p) {
    int n = strlen(s);
    int m = strlen(p);
    for (int i = 0; i + m <= n; ++i) {
        if (strncmp(s + i, p, m) == 0) return 1;
    }
    return 0;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char A[1010], B[1010]; scanf("%s", A); scanf("%s", B);
        if(strcmp(A,B)==0){
            printf("0\n");
            continue;
        }
        int has000 = hasPattern(A, "000");
        int has111 = hasPattern(A, "111");
        if(!has000 || !has111){
            printf("-1\n");
            continue;
        }
        // try single whole‑string flip
        char C[1010];
        for(int i=0;i<N;i++) C[i] = (A[i]=='0')?'1':'0';
        C[N]='\0';
        if(strcmp(C,B)==0){
            printf("1\n1 %d\n", N);
            continue;
        }
        // three‑move construction
        printf("3\n1 %d\n1 %d\n%d %d\n", N, N, 1, N);
    }
    return 0;
}

