bool hasPattern(const string &s, const string &p){
    return s.find(p)!=string::npos;
}

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N; string A,B; cin>>A>>B;
        if(A==B){
            cout<<0<<"\n";
            continue;
        }
        bool has000 = hasPattern(A,"000");
        bool has111 = hasPattern(A,"111");
        if(!has000 || !has111){
            cout<<-1<<"\n";
            continue;
        }
        string flipped=A;
        for(char &c:flipped) c = (c=='0')?'1':'0';
        if(flipped==B){
            cout<<1<<"\n"<<1<<" "<<N<<"\n";
            continue;
        }
        // three‑move fallback (always valid under the constraints)
        cout<<3<<"\n"<<1<<" "<<N<<"\n"<<1<<" "<<N<<"\n"<<1<<" "<<N<<"\n";
    }
    return 0;
}

