import java.io.*;
import java.util.*;

public class Main {
    static boolean hasPattern(String s, String p){
        return s.contains(p);
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while(T-- > 0){
            int N = Integer.parseInt(br.readLine().trim());
            String A = br.readLine().trim();
            String B = br.readLine().trim();
            if(A.equals(B)){
                out.append("0\n");
                continue;
            }
            boolean has000 = hasPattern(A, "000");
            boolean has111 = hasPattern(A, "111");
            if(!has000 || !has111){
                out.append("-1\n");
                continue;
            }
            StringBuilder flipped = new StringBuilder();
            for(char c: A.toCharArray()) flipped.append(c=='0'?'1':'0');
            if(flipped.toString().equals(B)){
                out.append("1\n1 ").append(N).append('\n');
                continue;
            }
            out.append("3\n1 ").append(N).append('\n')
               .append("1 ").append(N).append('\n')
               .append("1 ").append(N).append('\n');
        }
        System.out.print(out.toString());
    }
}

